import React, { createContext, useContext, useState, useLayoutEffect } from 'react';
import { themes } from '../styles/theme';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  const [mode, setMode] = useState(() => localStorage.getItem('finify-mode') || 'dark');

  useLayoutEffect(() => {
    const root = window.document.documentElement;
    const currentTheme = themes[mode];

    if (currentTheme) {
      Object.entries(currentTheme).forEach(([prop, val]) => {
        root.style.setProperty(prop, val);
      });
      root.setAttribute('data-theme', mode);
      localStorage.setItem('finify-mode', mode);
    }
  }, [mode]);

  const toggleTheme = () => setMode(prev => (prev === 'dark' ? 'light' : 'dark'));

  return (
    <ThemeContext.Provider value={{ mode, isDarkMode: mode === 'dark', toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => useContext(ThemeContext);
